import 'package:http/http.dart' as http;
import 'dart:convert';

Future<void> fetchUserData(String token) async {
  final url = Uri.parse('https://api.example.com/user/profile');
  final headers = {'Authorization': 'Bearer $token'};

  try {
    final response = await http.get(url, headers: headers);
    if (response.statusCode == 200) {
      final data = json.decode(response.body);
      print('User Data: $data');
    } else {
      throw Exception('Failed to load user data: ${response.statusCode}');
    }
  } catch (e) {
    print('Error fetching user data: $e');
  }
}

Future<void> syncData(String token, Map<String, dynamic> data) async {
  final url = Uri.parse('https://api.example.com/data/sync');
  final headers = {'Authorization': 'Bearer $token'};
  final body = json.encode(data);

  try {
    final response = await http.post(url, headers: headers, body: body);
    if (response.statusCode == 200) {
      print('Data synced successfully');
    } else {
      throw Exception('Failed to sync data: ${response.statusCode}');
    }
  } catch (e) {
    print('Error syncing data: $e');
  }
}